      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT Id, Seller__r.ExternalId__c, ExternalId__c, StartDate__c, Status__c, Observation__c, Store__r.ExternalId__c, Type__c, WorkOrderLineItem__r.ExternalId__c, WorkOrder__c, WorkOrderLineItem__r.Scheduling__r.StartDate__c, WorkOrderLineItem__r.Quantity, WorkOrderLineItem__r.UnitPrice, WorkOrderLineItem__r.Discount, WorkOrderLineItem__r.DiscountValue__c, WorkOrderLineItem__r.ExecutionSector__c, WorkOrderLineItem__r.Status, WorkOrderLineItem__r.WorkOrderType__r.ExternalId__c, WorkOrderLineItem__r.PricebookEntry.Product2.ExternalId__c, WorkOrderLineItem__r.Description FROM Scheduling__c WHERE WorkOrder__r.Id = '" ++ vars.osId ++ "' AND RecordType.Name = 'Produtivo'",
